var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"STUDENT_EXTRA_B_TWINTAIL","text":{"KOREA":"으윽… 머리야.","JPN":"ううっ……頭が痛い……","ENG":"Ugh... My head...","TWN":"呃呃…我的頭…"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"괜찮아…? 정신이 들어?","JPN":"大丈夫……？　目は覚めたか？","ENG":"You good...? How are you holding up?","TWN":"還好嗎…？你醒了？"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"STUDENT_EXTRA_B_TWINTAIL","text":{"KOREA":"이 소리… 누가 싸우고 있는 건가?","JPN":"この音は……誰か戦っているのか？","ENG":"That noise... Is someone fighting?","TWN":"這個聲音是…有人在打架嗎？"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"학생회 사람들이 우릴 구하러 온 것 같아. 란체스터 학생회장도.","JPN":"生徒会の人たちが俺らを助けにきたようだ。ランチェスター生徒会長も。","ENG":"I think the Student Council is here to save us. The Student President is here too.","TWN":"好像是學生會的人和學生會長來救我們了。"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"STUDENT_EXTRA_B_TWINTAIL","text":{"KOREA":"시엘은…?","JPN":"シエルは……？","ENG":"What about Ciel...?","TWN":"希爾呢…？"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"우리랑 같이 있어. 부상이 심해서 아직 의식은 없지만…","JPN":"俺たちと一緒にいるぜ。酷いケガでまだ意識は戻っていないが……","ENG":"She's with us. She's badly injured and hasn't woken up yet...","TWN":"她和我們在一起，但她傷勢太重還沒恢復意識…"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"STUDENT_EXTRA_B_TWINTAIL","text":{"KOREA":"그런 꼴 사나운 짓을 저질러 놓고도… 또 다른 사람들의 도움을 받다니.","JPN":"あんな下劣極まりないことをしておいて……また他人から助けられるなんて。","ENG":"After what we've done... we're still getting helped by others...","TWN":"我們做出這麼過分的事…她們還願意來救我們。"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"STUDENT_EXTRA_B_TWINTAIL","text":{"KOREA":"한심해…","JPN":"俺たちはなんて情けないんだ……","ENG":"We're pathetic...","TWN":"我們真是糟糕…"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"한심하지 않아.","JPN":"情けなくなんかないさ。","ENG":"You're not pathetic.","TWN":"不需要感到內疚。"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"너흰 강해지기 위해, 너희가 할 수 있는 최선을 다 했을 뿐이잖아?","JPN":"お前たちは強くなるために、自分たちにできることを最大限やったまでだろう？","ENG":"All you wanted was to get stronger, and you did the best you could.","TWN":"你們只是盡自己的努力想要變強而已，不是嗎？"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"STUDENT_EXTRA_B_TWINTAIL","text":{"KOREA":"너…!","JPN":"お前は……！","ENG":"You...!","TWN":"你…！"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"이 자식! 우릴 속이다니!","JPN":"てめぇ！　俺たちを騙したな！","ENG":"You bastard! You tricked us!","TWN":"你這傢伙！竟敢騙我們！"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"하하, 이해 좀 해줘. 아직은 나도 말단직이라 상사가 시키면 어쩔 수 없거든.","JPN":"はは、理解してくれよ。僕だってまだ下っ端だから、上司にやらされたら従うしかないんだ。","ENG":"Haha, try to see it from my point of view. As a low-ranking member of this group, I have to follow my boss's orders.","TWN":"哈哈，你們就體諒我一下，畢竟我只是個基層員工，當然只能聽長官的命令囉。"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"STUDENT_EXTRA_B_TWINTAIL","text":{"KOREA":"처음부터… 우릴 전부 팔아넘길 셈이었던 거야?","JPN":"初めから……俺たちのこと売り渡すつもりだったのか？","ENG":"Were you... planning on betraying us and then selling us off from the start?","TWN":"你從一開始…就打算出賣我們吧？"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"애초에 저 이상한 사람들이랑 한통속이었던 거겠지.","JPN":"最初からあの変な連中とグルだったんだろ。","ENG":"He was in it with those strange people from the beginning.","TWN":"你和那些人原本就是一掛的吧？"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"으음- 유감스럽게도 한통속은 틀린 말이 아니네.","JPN":"うーん、申し訳ないけど、否定はしないかな。","ENG":"Hmm... You're not wrong about siding with them from the start.","TWN":"嗯嗯，你說的沒錯，我們確實是同一掛的。"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"하지만 걱정 마. 너희는 내가 풀어주고, 이것도 줄 테니까.","JPN":"でも心配しないで。お前たちのことは僕が解放し、これも渡す。","ENG":"But don't you worry. I'll free the both of you, and also give you this.","TWN":"但你們放心，我會放了你們，還給你們這個。"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};